from collections import defaultdict
import heapq

class Twitter:
    def __init__(self):
        self.time = 0
        self.tweets = defaultdict(list)
        self.follows = defaultdict(set)

    def postTweet(self, userId, tweetId):
        self.follows[userId].add(userId)
        self.tweets[userId].append((self.time, tweetId))
        self.time += 1

    def getNewsFeed(self, userId):
        self.follows[userId].add(userId)
        heap = []
        for user in self.follows[userId]:
            for time, tweet in self.tweets[user][-10:]:
                heapq.heappush(heap, (-time, tweet))
        return [tweet for _, tweet in heapq.nsmallest(10, heap)]

    def follow(self, followerId, followeeId):
        self.follows[followerId].add(followerId)
        self.follows[followerId].add(followeeId)

    def unfollow(self, followerId, followeeId):
        if followerId != followeeId:
            self.follows[followerId].discard(followeeId)

class Solution:
    def twitter(self, operations, values):
        obj = None
        out = []
        for op, args in zip(operations, values):
            if op == 'Twitter':
                obj = Twitter()
            elif op == 'postTweet':
                obj.postTweet(*args)
            elif op == 'getNewsFeed':
                out.append(obj.getNewsFeed(*args))
            elif op == 'follow':
                obj.follow(*args)
            elif op == 'unfollow':
                obj.unfollow(*args)
        return out
